dark.canvasScript:
let canvas, ctx, W, H;
const drops = [];
const MAX = 100;

function createDrop() {
  return {
    x: Math.random() * W,
    y: Math.random() * -H,
    w: 2 + (Math.random() * 2 | 0) * 2,
    h: 4 + (Math.random() * 4 | 0) * 2,
    speed: 1 + Math.random() * 3,
    color: ["#ffff00", "#ff0000", "#ffffff", "#ff4400"][Math.random() * 4 | 0],
    alpha: 0.3 + Math.random() * 0.4
  };
}

function init(c, w, h) {
  canvas = c; ctx = c.getContext('2d'); W = w; H = h;
  drops.length = 0;
  for (let i = 0; i < MAX; i++) {
    const d = createDrop();
    d.y = Math.random() * H;
    drops.push(d);
  }
}

function draw() {
  ctx.fillStyle = 'rgba(100, 0, 0, 0.06)';
  ctx.fillRect(0, 0, W, H);
  for (let i = 0; i < drops.length; i++) {
    const d = drops[i];
    d.y += d.speed;
    if (d.y > H) {
      drops[i] = createDrop();
      continue;
    }
    ctx.fillStyle = d.color;
    ctx.globalAlpha = d.alpha;
    ctx.fillRect(d.x | 0, d.y | 0, d.w, d.h);
    ctx.globalAlpha = 1;
  }
  requestAnimationFrame(draw);
}

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = function(e) {
  const { type, canvas: c, width, height } = e.data;
  switch (type) {
    case 'init': init(c, width, height); draw(); break;
    case 'resize': W = width; H = height; if (canvas) { canvas.width = W; canvas.height = H; } break;
    case 'mousemove': break;
  }
};

